import sys

def main():
    count = 0
    try:
        with open('numbers.txt', 'r') as f:
            for line in f:
                stripped = line.strip()
                if not stripped:
                    continue
                # Handle possible negative numbers and leading signs
                try:
                    num = int(stripped)
                except ValueError:
                    continue  # skip lines that are not integers
                if num % 2 == 0:
                    count += 1
    except FileNotFoundError:
        print("numbers.txt not found", file=sys.stderr)
        sys.exit(1)
    print(count)

if __name__ == "__main__":
    main()

